import{_ as t,o as e,c as l,a2 as r}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"查理·芒格（Charlie Munger）","description":"","frontmatter":{},"headers":[],"relativePath":"04_people/查理·芒格.md","filePath":"04_people/查理·芒格.md"}'),o={name:"04_people/查理·芒格.md"};function i(h,a,d,n,u,c){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="查理·芒格-charlie-munger" tabindex="-1">查理·芒格（Charlie Munger） <a class="header-anchor" href="#查理·芒格-charlie-munger" aria-label="Permalink to &quot;查理·芒格（Charlie Munger）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>全名</td><td>Charles T. Munger</td></tr><tr><td>出生</td><td>1924年</td></tr><tr><td>逝世</td><td>2023年（99岁）</td></tr><tr><td>公司</td><td><a href="./../03_公司库/伯克希尔哈撒韦.html">伯克希尔·哈撒韦</a></td></tr><tr><td>职位</td><td>副董事长</td></tr></tbody></table><h2 id="职业生涯" tabindex="-1">职业生涯 <a class="header-anchor" href="#职业生涯" aria-label="Permalink to &quot;职业生涯&quot;">​</a></h2><h3 id="早期" tabindex="-1">早期 <a class="header-anchor" href="#早期" aria-label="Permalink to &quot;早期&quot;">​</a></h3><ul><li>洛杉矶律师，后转为投资</li><li>1962年创办Wheeler, Munger &amp; Co.投资合伙</li><li>1978年通过蓝筹印花与巴菲特正式合并</li></ul><h3 id="伯克希尔" tabindex="-1">伯克希尔 <a class="header-anchor" href="#伯克希尔" aria-label="Permalink to &quot;伯克希尔&quot;">​</a></h3><ul><li>1978年起担任副董事长</li><li>与巴菲特共同管理伯克希尔</li><li>负责吸引、留住优秀经理人</li></ul><h2 id="管理哲学" tabindex="-1">管理哲学 <a class="header-anchor" href="#管理哲学" aria-label="Permalink to &quot;管理哲学&quot;">​</a></h2><h3 id="核心观点" tabindex="-1">核心观点 <a class="header-anchor" href="#核心观点" aria-label="Permalink to &quot;核心观点&quot;">​</a></h3><ol><li><strong>研究失败比研究成功更有用</strong>（1990年代后多次提及）</li><li><strong>避免做蠢事</strong>胜过努力做聪明事</li><li><strong>多元思维模型</strong>（lollapalooza effect）</li><li><strong>耐心等待好球</strong></li></ol><h3 id="与巴菲特互补" tabindex="-1">与巴菲特互补 <a class="header-anchor" href="#与巴菲特互补" aria-label="Permalink to &quot;与巴菲特互补&quot;">​</a></h3><table tabindex="0"><thead><tr><th>巴菲特</th><th>芒格</th></tr></thead><tbody><tr><td>更乐观</td><td>更理性批判</td></tr><tr><td>数字导向</td><td>定性分析强</td></tr><tr><td>公众形象</td><td>幕后思考</td></tr></tbody></table><h2 id="巴菲特评价摘录" tabindex="-1">巴菲特评价摘录 <a class="header-anchor" href="#巴菲特评价摘录" aria-label="Permalink to &quot;巴菲特评价摘录&quot;">​</a></h2><h3 id="_1983年股东信" tabindex="-1">1983年股东信 <a class="header-anchor" href="#_1983年股东信" aria-label="Permalink to &quot;1983年股东信&quot;">​</a></h3><blockquote><p>&quot;查理·芒格和我在做管理合伙人工作，管理伯克希尔的所有控股企业。这工作我们享受得几乎罪过。&quot;</p></blockquote><blockquote><p>&quot;我们之间的商业决策可以互换——打个电话比开半天委员会会议更有效。&quot;</p></blockquote><h3 id="_1984年股东信" tabindex="-1">1984年股东信 <a class="header-anchor" href="#_1984年股东信" aria-label="Permalink to &quot;1984年股东信&quot;">​</a></h3><blockquote><p>&quot;查理·芒格强调研究错误比研究成功更重要。&quot;</p></blockquote><h3 id="_1987年股东信" tabindex="-1">1987年股东信 <a class="header-anchor" href="#_1987年股东信" aria-label="Permalink to &quot;1987年股东信&quot;">​</a></h3><blockquote><p>&quot;查理和我共同负责两件事：吸引和留住优秀经理人，配置资本。&quot;</p></blockquote><h2 id="重要贡献" tabindex="-1">重要贡献 <a class="header-anchor" href="#重要贡献" aria-label="Permalink to &quot;重要贡献&quot;">​</a></h2><h3 id="具体案例" tabindex="-1">具体案例 <a class="header-anchor" href="#具体案例" aria-label="Permalink to &quot;具体案例&quot;">​</a></h3><ul><li>建议买入喜诗糖果（1972年）</li><li>帮助韦斯考金融重新定位（1970年代）</li><li>推动1983年蓝筹印花与伯克希尔合并</li></ul><h3 id="思想贡献" tabindex="-1">思想贡献 <a class="header-anchor" href="#思想贡献" aria-label="Permalink to &quot;思想贡献&quot;">​</a></h3><ul><li>说服巴菲特从&quot;便宜买差企业&quot;转向&quot;合理价买好企业&quot;</li><li>多元思维模型框架</li><li>逆向思考方法</li></ul><h2 id="股东指定捐赠项目" tabindex="-1">股东指定捐赠项目 <a class="header-anchor" href="#股东指定捐赠项目" aria-label="Permalink to &quot;股东指定捐赠项目&quot;">​</a></h2><blockquote><p>&quot;股东指定捐赠项目是查理的想法。&quot; —— 1981年股东信</p></blockquote><h2 id="在股东信中的年份" tabindex="-1">在股东信中的年份 <a class="header-anchor" href="#在股东信中的年份" aria-label="Permalink to &quot;在股东信中的年份&quot;">​</a></h2><p>1978, 1979, 1980, 1981, 1982, 1983, 1984, 1985, 1986, 1987</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/伯克希尔哈撒韦.html">伯克希尔·哈撒韦</a> - 服务的企业</li><li><a href="./沃伦·巴菲特.html">沃伦·巴菲特</a> - 搭档</li><li><a href="./../03_公司库/蓝筹印花.html">蓝筹印花</a> - 合并前主体</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',34)])])}const b=t(o,[["render",i]]);export{q as __pageData,b as default};
